from django import templatefrom django.db.models.aggregates import Countfrom django.utils.safestring import mark_safe# from ..models import Comment,Postfrom blog.models import Comment, Postfrom markdown import markdownregister = template.Library()@register.simple_tag()def total_comment():    return Comment.objects.filter(active=True).count()@register.simple_tag()def total_post():    return Post.published.count()@register.simple_tag()def most_popular_post(count=3):    return Post.published.annotate(comment_counts=Count('comments')).order_by('-comment_counts')[:count]@register.filter(name="markdown")def to_markdown(text):    return mark_safe(markdown(text))@register.simple_tag()def last_post_date():    post = Post.published.order_by('-publish').first()    return post.publish if post else "-"@register.inclusion_tag("partials/latest_post.html")def latest_post(count=4):    l_post = Post.published.order_by('-publish')[:count]    return { 'l_post':l_post}